def longestSemiRepetitiveSubstring(s: str) -> int:
    n = len(s)
    max_len = 1
    for i in range(1, n):
        for j in range(i, n):
            if s[i] == s[j] and (i + 1 < n and s[i] == s[i + 1]):
                max_len = max(max_len, j - i + 1)
    return max_len

